public int round10(int num)
{
    // Find the remainder when num is divided by 10
    int remainder = num % 10;

    // If the remainder is 5 or more, round up
    if (remainder >= 5) {
        return num + (10 - remainder);
    } 
    // Otherwise, round down
    else {
        return num - remainder;
    }
}

