}

public int round10(int num) {
    // Get the last digit of the number
    int lastDigit = num % 10;

    // If the last digit is 5 or more, round up
    if (lastDigit >= 5) {
        return num + (10 - lastDigit);
    } else {
        // Otherwise, round down
        return num - lastDigit;
    }
}

