public boolean xyBalance(String str) {
    boolean seenY = false;
    for (int i = str.length() - 1; i >= 0; i--) {
        if (str.charAt(i) == 'y') {
            seenY = true;
        } else if (str.charAt(i) == 'x' && !seenY) {
            return false;
        }
    }
    return true;
}

