    boolean yFound = false;
    for (int i = str.length() - 1; i >= 0; i--) {
        if (str.charAt(i) == 'y') {
            yFound = true;
        } else if (str.charAt(i) == 'x' && !yFound) {
            return false;
        }
    }
    return true;
}

