public int sum13(int[] nums) {
    int sum = 0;
    for (int i = 0; i < nums.length; i++) {
        // Skip the number 13
        if (nums[i] == 13) {
            continue;
        }
        // Check if the previous number was 13, if yes, skip this number
        if (i > 0 && nums[i - 1] == 13) {
            continue;
        }
        // Add the number to the sum
        sum += nums[i];
    }
    return sum;
}

