public int round10(int num) {
    // Get the rightmost digit of the number
    int rightmostDigit = num % 10;

    // If the rightmost digit is 5 or more, round up
    if (rightmostDigit >= 5) {
        return ((num / 10) + 1) * 10;
    } 
    // Otherwise, round down
    else {
        return (num / 10) * 10;
    }
}

