public boolean in1To10(int n, boolean outsideMode) {
    if (outsideMode) {
        // Check if n is outside the range 2 to 9
        return n <= 1 || n >= 10;
    } else {
        // Check if n is within the range 1 to 10
        return n >= 1 && n <= 10;
    }
}

