public int centeredAverage(int[] nums) {
    int min = nums[0];
    int max = nums[0];
    int sum = 0;
    for (int num : nums) {
        if (num < min) min = num;
        if (num > max) max = num;
        sum += num;
    }
    sum -= min;
    sum -= max;
    return sum / (nums.length - 2);
}

